if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const pursue = $('Fetch Forecasts').all().map(i => i.json);
const evaluate = $('Fetch Opps').all().map(i => i.json);
const trends = $('Fetch Trends Data').all().map(i => i.json);

var trendsByDate = {};
trends.forEach(function(t) {
  var d = String(t.date || '').substring(0, 10);
  if (!trendsByDate[d]) trendsByDate[d] = {};
  trendsByDate[d][t.metric_name] = t.metric_value;
});
var trendSummary = Object.keys(trendsByDate).sort().reverse().slice(0, 14).map(function(d) {
  var m = trendsByDate[d];
  return d + ': opps=' + (m.total_opportunities||0) + ', pipeline=$' + (m.pipeline_value||0) + ', avg_score=' + (m.avg_gda_score||0);
}).join('\n');

var totalValue = pursue.concat(evaluate).reduce((s,o) => s+(parseInt(o.estimated_value)||0), 0);
var avgScore = pursue.length ? Math.round(pursue.reduce((s,o) => s+(parseInt(o.gda_score)||0),0)/pursue.length) : 0;
var deptCounts = {};
pursue.concat(evaluate).forEach(o => { var d=o.level_1||'Unknown'; deptCounts[d]=(deptCounts[d]||0)+1; });
var topDept = Object.entries(deptCounts).sort((a,b)=>b[1]-a[1])[0];
var recompetes = pursue.concat(evaluate).filter(o => o.incumbent_analysis && o.incumbent_analysis.length > 5);
var uncovered = pursue.concat(evaluate).filter(o => !o.has_capture_plan);

const prompt = [
  'PREDICTIVE INTELLIGENCE ANALYSIS — Georgetown Defense Analytics (GDA)',
  'Generated: ' + new Date().toISOString(),
  '',
  'GDA operates three OUs targeting defense acquisition:',
  '- Enable/Envision: XR, simulation, training, LVC (SOCOM, TRADOC, PEO STRI)',
  '- Train/PD Systems: C5ISR, AI/ML, logistics (Army Futures Command, INSCOM)',  
  '- Protect/Riverstone: SIGINT, cyber, DevSecOps (CYBERCOM, DISA, INDOPACOM)',
  'Target agencies: SOCOM, TRADOC/PEO STRI, Army Futures Command, INSCOM, CYBERCOM, DISA, MDA, INDOPACOM',
  'Must-win recompetes: IEW&S SETA (W56KGY22F0028), all incumbent contracts',
  '',
  '=== LIVE PIPELINE SUMMARY ===',
  'PURSUE (' + pursue.length + ' opps): ' + pursue.slice(0,8).map(o => (o.opp_title||'Untitled').substring(0,60) + ' [' + o.agency + ' | $' + Math.round((parseInt(o.estimated_value)||0)/1000000) + 'M | score:' + o.gda_score + ']').join(' | '),
  'EVALUATE (' + evaluate.length + ' opps): ' + evaluate.slice(0,8).map(o => (o.opp_title||'Untitled').substring(0,50) + ' [' + o.agency + ' | score:' + o.gda_score + ']').join(' | '),
  'Pipeline value: $' + Math.round(totalValue/1000000) + 'M | Avg PURSUE score: ' + avgScore,
  'Top dept: ' + (topDept ? topDept[0] + ' (' + topDept[1] + ' opps)' : 'N/A'),
  'Recompetes with incumbent intel: ' + recompetes.length,
  'Active opps without capture plans: ' + uncovered.length,
  '',
  '=== INCUMBENT THREAT INTEL ===',
  recompetes.slice(0,5).map(o => (o.opp_title||'').substring(0,50) + ' — ' + (o.incumbent_analysis||'').substring(0,100)).join('\n') || '(none)',
  '',
  '=== COMPETITOR INTEL ===',
  pursue.filter(o=>o.likely_competitors).slice(0,5).map(o => (o.opp_title||'').substring(0,40) + ': ' + (o.likely_competitors||'').substring(0,80)).join('\n') || '(none)',
  '',
  '=== TREND DATA (last 14 days) ===',
  trendSummary || '(collecting)',
  '',
  'Generate predictive intelligence based on THIS actual GDA pipeline data. Return ONLY valid JSON, no markdown:',
  '{',
  '  "rfp_forecasts": [{"program": "exact opp title from data", "agency": "agency", "probability": 0-100, "timeline": "Q3 FY2026", "estimated_value": "$XM", "gda_relevance": "HIGH|MEDIUM|LOW", "ou_owner": "Enable|Train|Protect", "rationale": "specific reason based on data"}],',
  '  "capture_gaps": [{"opp_title": "title", "agency": "agency", "gda_score": 0, "gap": "what capture action is missing", "urgency": "CRITICAL|HIGH|MEDIUM"}],',
  '  "competitor_threats": [{"competitor": "name", "threat_level": "HIGH|MEDIUM|LOW", "affected_opps": ["opp title"], "countermeasure": "action"}],',
  '  "recommended_actions": ["specific BD action tied to a real opp or agency in the pipeline"],',
  '  "pipeline_health": {"pursue_count": 0, "evaluate_count": 0, "total_value_m": 0, "capture_coverage_pct": 0, "top_risk": "string"},',
  '  "generated_at": "ISO timestamp"',
  '}',
  '',
  'Requirements: 5 RFP forecasts from PURSUE/EVALUATE opps above. 5 capture gaps from uncovered opps. 3 competitor threats from intel above.',
  'All data MUST reference actual opps, agencies, and competitors from the pipeline above. No invented data.'
].join('\n');

return [{ json: { prompt, pursue_count: pursue.length, evaluate_count: evaluate.length, trend_days: Object.keys(trendsByDate).length } }];

var item = $input.first().json;
var data = (item.content && item.content[0] && item.content[0].text) ? item.content[0].text : (item.output || JSON.stringify(item));
var start = data.indexOf('{');
var end = data.lastIndexOf('}');
var parsed = {};

try {
  if (start !== -1 && end !== -1) {
    parsed = JSON.parse(data.substring(start, end + 1));
  } else {
    parsed = { error: 'No JSON found', raw: data.substring(0, 500) };
  }
} catch(e) {
  try {
    var repaired = data.substring(start, end + 1).replace(/[\u2018\u2019]/g, "'").replace(/[\u201C\u201D]/g, '"').replace(/,\s*}/g, '}').replace(/,\s*]/g, ']');
    parsed = JSON.parse(repaired);
  } catch(e2) {
    parsed = { error: 'Parse failed: ' + e2.message, raw: data.substring(0, 500) };
  }
}

// Ensure all arrays are flat strings for React safety
if (parsed.rfp_forecasts) {
  parsed.rfp_forecasts = parsed.rfp_forecasts.map(function(f) {
    return {
      program: String(f.program || ''),
      agency: String(f.agency || ''),
      probability: Number(f.probability || 0),
      timeline: String(f.timeline || ''),
      estimated_value: String(f.estimated_value || ''),
      eis_relevance: String(f.eis_relevance || 'MEDIUM'),
      rationale: String(f.rationale || '')
    };
  });
}
if (parsed.capability_gaps) {
  parsed.capability_gaps = parsed.capability_gaps.map(function(g) {
    return {
      title: String(g.title || ''),
      description: String(g.description || ''),
      recent_activity: String(g.recent_activity || ''),
      affected_agencies: (g.affected_agencies || []).map(String),
      eis_fit: String(g.eis_fit || '')
    };
  });
}
if (parsed.recommended_focus_areas) {
  parsed.recommended_focus_areas = parsed.recommended_focus_areas.map(String);
}
if (parsed.risk_factors) {
  parsed.risk_factors = parsed.risk_factors.map(String);
}

parsed.generated_at = parsed.generated_at || new Date().toISOString();
parsed.status = 'ok';
parsed.action = 'predictive';

return [{ json: parsed }];
